import{c as t,Z as r,Q as o,j as l,o as i,m as d}from"./chunks/framework.qjzPVSkb.js";const q=JSON.parse('{"title":"Cursor","description":"AI 原生 IDE——基于 VS Code，内置 AI 补全、对话、多文件编辑，让编程效率倍增","frontmatter":{"title":"Cursor","description":"AI 原生 IDE——基于 VS Code，内置 AI 补全、对话、多文件编辑，让编程效率倍增","difficulty":"intermediate"},"headers":[],"relativePath":"tools/cursor.md","filePath":"tools/cursor.md"}'),s={name:"tools/cursor.md"};function n(h,a,u,c,b,m){const e=r("DifficultyBadge");return o(),l("div",null,[i(e,{level:"intermediate"}),a[0]||(a[0]=d('<h1 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>AI 原生 IDE</strong>——基于 VS Code 深度改造，将 AI 融入编程的每一个环节，是目前最受欢迎的 AI 编程工具。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>公司</td><td>Anysphere</td></tr><tr><td>价格</td><td>免费版 / Pro $20/月 / Business $40/人/月</td></tr><tr><td>支持模型</td><td>GPT-5 / Claude 4 / Claude 3.5 Sonnet / 自定义 API</td></tr><tr><td>平台</td><td>macOS / Windows / Linux</td></tr><tr><td>基于</td><td>VS Code（开源分支）</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="⌨️-tab-补全" tabindex="-1">⌨️ Tab 补全 <a class="header-anchor" href="#⌨️-tab-补全" aria-label="Permalink to &quot;⌨️ Tab 补全&quot;">​</a></h3><p>在编码时，Cursor 会自动预测你的下一行代码。按 Tab 接受，继续写继续预测。补全质量极高，能理解上下文意图。</p><h3 id="✨-ctrl-k-内联编辑" tabindex="-1">✨ Ctrl+K 内联编辑 <a class="header-anchor" href="#✨-ctrl-k-内联编辑" aria-label="Permalink to &quot;✨ Ctrl+K 内联编辑&quot;">​</a></h3><p>选中一段代码 → 按 <code>Ctrl+K</code>（Mac: <code>Cmd+K</code>）→ 输入你的需求（如&quot;添加错误处理&quot;&quot;改成 async/await 写法&quot;），Cursor 直接原地修改。</p><h3 id="💬-chat-对话" tabindex="-1">💬 Chat 对话 <a class="header-anchor" href="#💬-chat-对话" aria-label="Permalink to &quot;💬 Chat 对话&quot;">​</a></h3><p>侧边栏内嵌 AI 对话，可以：</p><ul><li>选中代码提问&quot;这段代码在做什么？&quot;</li><li>让 AI 解释报错信息</li><li>讨论技术方案</li></ul><h3 id="🎼-composer-多文件编辑" tabindex="-1">🎼 Composer 多文件编辑 <a class="header-anchor" href="#🎼-composer-多文件编辑" aria-label="Permalink to &quot;🎼 Composer 多文件编辑&quot;">​</a></h3><p>Composer 是 Cursor 的杀手级功能——可以一次性修改多个文件，自动创建新文件，完成跨文件的复杂重构。</p><h3 id="📋-上下文感知" tabindex="-1">📋 上下文感知 <a class="header-anchor" href="#📋-上下文感知" aria-label="Permalink to &quot;📋 上下文感知&quot;">​</a></h3><p>Cursor 会分析整个项目结构，自动将相关文件加入 AI 的上下文中。你也可以用 <code>@</code> 标记手动指定文件、文件夹、文档等作为上下文。</p><h3 id="🏷️-rules-规则" tabindex="-1">🏷️ Rules 规则 <a class="header-anchor" href="#🏷️-rules-规则" aria-label="Permalink to &quot;🏷️ Rules 规则&quot;">​</a></h3><p>可以在项目根目录创建 <code>.cursorrules</code> 文件，定义项目规范、代码风格等偏好，Cursor 会在所有 AI 交互中遵守这些规则。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>AI 融入最深</strong>：不止是代码补全，而是整个开发流程的 AI 化</li><li><strong>基于 VS Code</strong>：熟悉的界面，所有 VS Code 插件都能用</li><li><strong>Composer</strong>：多文件编辑能力远超同类产品</li><li><strong>模型选择自由</strong>：可以用 GPT-4o、Claude、甚至自己的 API Key</li><li><strong>上下文管理</strong>：@ 标记系统让上下文控制非常精准</li></ul><h2 id="不足" tabindex="-1">不足 <a class="header-anchor" href="#不足" aria-label="Permalink to &quot;不足&quot;">​</a></h2><ul><li>Pro 版有月度请求限额（500 次 fast requests / 月）</li><li>对网络要求较高（所有 AI 功能都需联网）</li><li>偶尔会过度 AI 化（Tab 补全太多可能干扰思路）</li><li>不是完全开源</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><ul><li>✅ 日常编程开发的开发者</li><li>✅ 需要频繁重构、跨文件修改的场景</li><li>✅ 从 VS Code 迁移过来的用户</li><li>✅ 中高级开发者（能判断 AI 代码质量）</li><li>⚠️ 完全新手建议先学基础，再借助 AI 加速</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><ol><li><a href="https://cursor.sh" target="_blank" rel="noreferrer">下载 Cursor</a> 并安装</li><li>登录账号（支持 GitHub 登录）</li><li>打开任意项目文件夹</li><li>开始编码，Tab 补全会自动触发</li><li>按 <code>Ctrl+K</code> 试试内联编辑</li><li>按 <code>Ctrl+L</code> 打开 Chat 面板</li></ol><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/practices/cursor-website.html">用 Cursor 搭建网页</a> —— 实战教程</li><li><a href="/ai-knowledge/tools/copilot.html">GitHub Copilot</a> —— 另一款主流 AI 编程工具对比</li><li><a href="/ai-knowledge/terms/function-calling.html">Function Calling</a>、<a href="/ai-knowledge/terms/agent.html">Agent</a></li></ul><hr><blockquote><p>最后更新：2026.05</p></blockquote>',31))])}const C=t(s,[["render",n]]);export{q as __pageData,C as default};
